// logistics_new_messages.go — hand-written proto message types for
// ShipFulfillmentTask, GeneratePickupQR, and RedeemPickupQR RPCs.
//
// NOTE: These types would normally be generated by protoc from logistics.proto.
// They are written by hand because protoc is not available in the sandbox.
// Run `make genpb` to regenerate cleanly from logistics.proto once protoc is
// available in the build environment.
//
// BL-LOG-002: ShipFulfillmentTask — creates shipment + tracking number.
// BL-LOG-003: GeneratePickupQR + RedeemPickupQR — single-use QR with 7d TTL.

package pb

// ShipFulfillmentTaskRequest carries the booking context needed to ship a kit.
type ShipFulfillmentTaskRequest struct {
	BookingId string
	Carrier   string // defaults to "manual" if empty
	Notes     string
}

func (x *ShipFulfillmentTaskRequest) GetBookingId() string {
	if x == nil {
		return ""
	}
	return x.BookingId
}
func (x *ShipFulfillmentTaskRequest) GetCarrier() string {
	if x == nil {
		return ""
	}
	return x.Carrier
}
func (x *ShipFulfillmentTaskRequest) GetNotes() string {
	if x == nil {
		return ""
	}
	return x.Notes
}

// ShipFulfillmentTaskResponse returns the created (or existing) shipment.
type ShipFulfillmentTaskResponse struct {
	ShipmentId     string
	TrackingNumber string
	Status         string // "shipped"
}

func (x *ShipFulfillmentTaskResponse) GetShipmentId() string {
	if x == nil {
		return ""
	}
	return x.ShipmentId
}
func (x *ShipFulfillmentTaskResponse) GetTrackingNumber() string {
	if x == nil {
		return ""
	}
	return x.TrackingNumber
}
func (x *ShipFulfillmentTaskResponse) GetStatus() string {
	if x == nil {
		return ""
	}
	return x.Status
}

// GeneratePickupQRRequest requests a single-use pickup QR token.
type GeneratePickupQRRequest struct {
	BookingId string
}

func (x *GeneratePickupQRRequest) GetBookingId() string {
	if x == nil {
		return ""
	}
	return x.BookingId
}

// GeneratePickupQRResponse returns the generated pickup token.
type GeneratePickupQRResponse struct {
	PickupTokenId string
	Token         string
	ExpiresAt     string // RFC3339 timestamp
}

func (x *GeneratePickupQRResponse) GetPickupTokenId() string {
	if x == nil {
		return ""
	}
	return x.PickupTokenId
}
func (x *GeneratePickupQRResponse) GetToken() string {
	if x == nil {
		return ""
	}
	return x.Token
}
func (x *GeneratePickupQRResponse) GetExpiresAt() string {
	if x == nil {
		return ""
	}
	return x.ExpiresAt
}

// RedeemPickupQRRequest carries the token to redeem.
type RedeemPickupQRRequest struct {
	Token string
}

func (x *RedeemPickupQRRequest) GetToken() string {
	if x == nil {
		return ""
	}
	return x.Token
}

// RedeemPickupQRResponse returns the result of redeeming the token.
type RedeemPickupQRResponse struct {
	Redeemed    bool
	BookingId   string
	TaskId      string
	ErrorReason string // non-empty if Redeemed=false
}

func (x *RedeemPickupQRResponse) GetRedeemed() bool {
	if x == nil {
		return false
	}
	return x.Redeemed
}
func (x *RedeemPickupQRResponse) GetBookingId() string {
	if x == nil {
		return ""
	}
	return x.BookingId
}
func (x *RedeemPickupQRResponse) GetTaskId() string {
	if x == nil {
		return ""
	}
	return x.TaskId
}
func (x *RedeemPickupQRResponse) GetErrorReason() string {
	if x == nil {
		return ""
	}
	return x.ErrorReason
}
